@page "/category/{CategorySlug}"
@using RecipeShare.Models
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>@categoryName - RecipeShare</PageTitle>

<h1>@categoryName</h1>

@if (recipes.Count == 0)
{
    <p>No recipes found in this category.</p>
}
else
{
    <div class="row">
        @foreach (var recipe in recipes)
        {
            <div class="col-md-6 mb-3">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text">@recipe.Description</p>
                        <p class="text-muted">
                            ⭐ @recipe.AverageRating / 5 (@recipe.RatingCount ratings)
                        </p>
                        <a href="/recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

<a href="/" class="btn btn-outline-secondary mt-3">← Back to Categories</a>

@code {
    [Parameter] public string CategorySlug { get; set; } = string.Empty;

    private List<Recipe> recipes = [];
    private string categoryName = string.Empty;

    protected override void OnParametersSet()
    {
        recipes = RecipeService.GetByCategory(CategorySlug);
        var categories = RecipeService.GetCategories();
        categoryName = categories.GetValueOrDefault(CategorySlug, CategorySlug);
    }
}

@page "/recipe/{Id:int}"
@using RecipeShare.Models
@using RecipeShare.Services
@inject RecipeService RecipeService

@if (recipe is null)
{
    <PageTitle>Recipe Not Found - RecipeShare</PageTitle>
    <h1>Recipe Not Found</h1>
    <p>Sorry, we couldn't find that recipe.</p>
}
else
{
    <PageTitle>@recipe.Title - RecipeShare</PageTitle>

    <h1>@recipe.Title</h1>
    <p class="lead">@recipe.Description</p>

    <div class="row">
        <div class="col-md-8">
            <h3>Ingredients</h3>
            <ul>
                @foreach (var ingredient in recipe.Ingredients)
                {
                    <li>@ingredient</li>
                }
            </ul>

            <h3>Steps</h3>
            <ol>
                @foreach (var step in recipe.Steps)
                {
                    <li class="mb-2">@step</li>
                }
            </ol>
        </div>
        <div class="col-md-4">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">Rate This Recipe</h5>
                    <p class="text-muted">
                        Current: ⭐ @recipe.AverageRating / 5 (@recipe.RatingCount ratings)
                    </p>
                    <StarRating RecipeId="recipe.Id" @rendermode="InteractiveServer" />
                </div>
            </div>
        </div>
    </div>

    <a href="/category/@recipe.Category" class="btn btn-outline-secondary mt-3">← Back to Category</a>
}

@code {
    [Parameter] public int Id { get; set; }

    private Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetById(Id);
    }
}

@using RecipeShare.Services
@inject RecipeService RecipeService
@rendermode InteractiveServer

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= selectedRating ? "selected" : "")"
              @onclick="() => Rate(star)"
              role="button"
              title="Rate @star star(s)">
            @(star <= selectedRating ? "★" : "☆")
        </span>
    }
</div>

@if (submitted)
{
    <p class="text-success mt-2">Thanks for rating!</p>
}

<style>
    .star-rating .star {
        font-size: 1.8rem;
        cursor: pointer;
        color: #ccc;
        transition: color 0.2s;
    }
    .star-rating .star.selected {
        color: #ffc107;
    }
    .star-rating .star:hover {
        color: #ffdb4d;
    }
</style>

@code {
    [Parameter] public int RecipeId { get; set; }

    private int selectedRating;
    private bool submitted;

    private void Rate(int stars)
    {
        selectedRating = stars;
        RecipeService.AddRating(RecipeId, stars);
        submitted = true;
    }
}

