@page "/submit"
@using RecipeShare.Models
@using RecipeShare.Services
@inject RecipeService RecipeService
@rendermode InteractiveServer

<PageTitle>Submit a Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (isSubmitted)
{
    <div class="alert alert-success">
        <h4>Recipe Submitted!</h4>
        <p>Thank you for sharing "<strong>@submission.Title</strong>" with the community.</p>
        <button class="btn btn-primary" @onclick="Reset">Submit Another</button>
    </div>
}
else
{
    <EditForm Model="submission" OnValidSubmit="HandleSubmit" FormName="recipeForm">
        <div class="row">
            <div class="col-md-8">
                <div class="mb-3">
                    <label for="title" class="form-label">Recipe Title</label>
                    <InputText id="title" @bind-Value="submission.Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
                </div>

                <div class="mb-3">
                    <label for="category" class="form-label">Category</label>
                    <InputSelect id="category" @bind-Value="submission.Category" class="form-select">
                        <option value="">-- Select a category --</option>
                        <option value="appetizers">Appetizers</option>
                        <option value="main-courses">Main Courses</option>
                        <option value="desserts">Desserts</option>
                        <option value="beverages">Beverages</option>
                        <option value="breads">Breads & Baking</option>
                        <option value="salads">Salads</option>
                    </InputSelect>
                </div>

                <div class="mb-3">
                    <label for="ingredients" class="form-label">Ingredients</label>
                    <InputTextArea id="ingredients" @bind-Value="submission.Ingredients" class="form-control" rows="6"
                        placeholder="Enter each ingredient on a new line" />
                    <div class="form-text">One ingredient per line.</div>
                </div>

                <div class="mb-3">
                    <label for="steps" class="form-label">Preparation Steps</label>
                    <InputTextArea id="steps" @bind-Value="submission.Steps" class="form-control" rows="6"
                        placeholder="Enter each step on a new line" />
                    <div class="form-text">One step per line.</div>
                </div>

                <button type="submit" class="btn btn-success"
                    disabled="@(string.IsNullOrWhiteSpace(submission.Title) || string.IsNullOrWhiteSpace(submission.Category))">
                    Submit Recipe
                </button>
            </div>
        </div>
    </EditForm>
}

@code {
    private RecipeSubmission submission = new();
    private bool isSubmitted;

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(submission.Title) || string.IsNullOrWhiteSpace(submission.Category))
            return;

        RecipeService.SubmitRecipe(submission);
        isSubmitted = true;
    }

    private void Reset()
    {
        submission = new RecipeSubmission();
        isSubmitted = false;
    }
}

