using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes =
    [
        new()
        {
            Id = 1, Title = "Bruschetta", Category = "appetizers",
            Description = "Classic Italian appetizer with tomatoes and basil on toasted bread.",
            Ingredients = ["4 slices crusty bread", "2 ripe tomatoes, diced", "Fresh basil leaves", "2 cloves garlic", "Olive oil", "Salt and pepper"],
            Steps = ["Toast bread slices until golden.", "Rub garlic on warm toast.", "Mix tomatoes with basil, oil, salt, and pepper.", "Spoon tomato mixture onto toast. Serve immediately."],
            AverageRating = 4.5, RatingCount = 12
        },
        new()
        {
            Id = 2, Title = "Stuffed Mushrooms", Category = "appetizers",
            Description = "Savory mushroom caps filled with cream cheese and herbs.",
            Ingredients = ["12 button mushrooms", "100g cream cheese", "2 tbsp breadcrumbs", "1 clove garlic, minced", "Fresh parsley", "Parmesan cheese"],
            Steps = ["Remove mushroom stems and hollow caps.", "Mix cream cheese, garlic, breadcrumbs, and parsley.", "Fill caps with mixture and top with Parmesan.", "Bake at 180°C for 20 minutes."],
            AverageRating = 4.2, RatingCount = 8
        },
        new()
        {
            Id = 3, Title = "Spaghetti Carbonara", Category = "main-courses",
            Description = "Classic Roman pasta with eggs, cheese, and pancetta.",
            Ingredients = ["400g spaghetti", "200g pancetta", "4 egg yolks", "100g Pecorino Romano", "Black pepper"],
            Steps = ["Cook pasta in salted boiling water.", "Fry pancetta until crispy.", "Whisk egg yolks with grated cheese and pepper.", "Toss hot pasta with pancetta, then mix in egg mixture off heat.", "Serve immediately with extra cheese."],
            AverageRating = 4.8, RatingCount = 25
        },
        new()
        {
            Id = 4, Title = "Chicken Tikka Masala", Category = "main-courses",
            Description = "Tender chicken in a creamy spiced tomato sauce.",
            Ingredients = ["500g chicken breast", "200ml yogurt", "400ml tomato sauce", "200ml cream", "Garam masala", "Cumin, coriander, turmeric", "Garlic and ginger"],
            Steps = ["Marinate chicken in yogurt and spices for 2 hours.", "Grill chicken until charred.", "Simmer tomato sauce with spices.", "Add cream and grilled chicken.", "Cook for 10 minutes. Serve with rice or naan."],
            AverageRating = 4.6, RatingCount = 18
        },
        new()
        {
            Id = 5, Title = "Chocolate Lava Cake", Category = "desserts",
            Description = "Rich chocolate cake with a molten center.",
            Ingredients = ["200g dark chocolate", "150g butter", "3 eggs", "100g sugar", "50g flour", "Butter for ramekins"],
            Steps = ["Melt chocolate and butter together.", "Whisk eggs and sugar until fluffy.", "Fold chocolate mixture into eggs, then fold in flour.", "Pour into greased ramekins.", "Bake at 200°C for 12 minutes. Center should be soft."],
            AverageRating = 4.9, RatingCount = 30
        },
        new()
        {
            Id = 6, Title = "Tiramisu", Category = "desserts",
            Description = "Italian coffee-flavored layered dessert.",
            Ingredients = ["500g mascarpone", "4 eggs", "100g sugar", "300ml espresso", "Ladyfinger biscuits", "Cocoa powder"],
            Steps = ["Separate eggs. Beat yolks with sugar until pale.", "Mix mascarpone into yolk mixture.", "Whip egg whites and fold in gently.", "Dip ladyfingers in espresso and layer with cream.", "Refrigerate 4 hours. Dust with cocoa before serving."],
            AverageRating = 4.7, RatingCount = 22
        },
        new()
        {
            Id = 7, Title = "Mango Lassi", Category = "beverages",
            Description = "Creamy Indian yogurt drink with mango.",
            Ingredients = ["1 ripe mango", "200ml yogurt", "100ml milk", "2 tbsp sugar", "Pinch of cardamom"],
            Steps = ["Peel and chop mango.", "Blend mango, yogurt, milk, sugar, and cardamom until smooth.", "Serve chilled with ice."],
            AverageRating = 4.3, RatingCount = 10
        },
        new()
        {
            Id = 8, Title = "Sourdough Bread", Category = "breads",
            Description = "Artisan bread with a tangy flavor and crispy crust.",
            Ingredients = ["500g bread flour", "350ml water", "100g sourdough starter", "10g salt"],
            Steps = ["Mix flour, water, and starter. Rest 30 minutes.", "Add salt and knead until smooth.", "Bulk ferment 4-6 hours with stretch and folds.", "Shape and proof overnight in fridge.", "Bake in Dutch oven at 230°C for 45 minutes."],
            AverageRating = 4.4, RatingCount = 15
        },
        new()
        {
            Id = 9, Title = "Caesar Salad", Category = "salads",
            Description = "Crisp romaine with creamy Caesar dressing and croutons.",
            Ingredients = ["1 head romaine lettuce", "Caesar dressing", "Croutons", "Parmesan shavings", "Anchovy fillets (optional)"],
            Steps = ["Wash and chop romaine into bite-sized pieces.", "Toss with Caesar dressing.", "Top with croutons, Parmesan, and anchovies.", "Serve immediately."],
            AverageRating = 4.1, RatingCount = 9
        }
    ];

    private readonly Dictionary<int, List<int>> _ratings = [];

    public List<Recipe> GetByCategory(string category)
    {
        return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    public Recipe? GetById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public void AddRating(int recipeId, int stars)
    {
        if (stars < 1 || stars > 5) return;
        var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe is null) return;

        if (!_ratings.ContainsKey(recipeId))
            _ratings[recipeId] = [];

        _ratings[recipeId].Add(stars);
        var totalRatings = _ratings[recipeId].Count;
        recipe.RatingCount++;
        recipe.AverageRating = Math.Round((double)_ratings[recipeId].Sum() / totalRatings, 1);
    }

    public void SubmitRecipe(RecipeSubmission submission)
    {
        var newId = _recipes.Max(r => r.Id) + 1;
        _recipes.Add(new Recipe
        {
            Id = newId,
            Title = submission.Title,
            Category = submission.Category,
            Description = $"A community-submitted recipe for {submission.Title}.",
            Ingredients = submission.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries).ToList(),
            Steps = submission.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries).ToList(),
            AverageRating = 0,
            RatingCount = 0
        });
    }

    public Dictionary<string, string> GetCategories()
    {
        return new Dictionary<string, string>
        {
            ["appetizers"] = "Appetizers",
            ["main-courses"] = "Main Courses",
            ["desserts"] = "Desserts",
            ["beverages"] = "Beverages",
            ["breads"] = "Breads & Baking",
            ["salads"] = "Salads"
        };
    }
}

